import base64
from dataclasses import dataclass
from typing import List, Optional, Any


def encode_cursor(item_id: int) -> str:
    return base64.urlsafe_b64encode(f'cursor:{item_id}'.encode()).decode()


def decode_cursor(cursor: str) -> Optional[int]:
    if not cursor:
        return None
    try:
        decoded = base64.urlsafe_b64decode(cursor.encode()).decode()
        if decoded.startswith('cursor:'):
            return int(decoded.split(':')[1])
    except Exception:
        pass
    return None


@dataclass
class Page:
    items: List[Any]
    next_cursor: Optional[str]
    prev_cursor: Optional[str]


class CursorPaginator:
    def __init__(self, items: List[dict], page_size: int = 20):
        self.items = items
        self.page_size = page_size

    def get_page(self, after: Optional[str] = None, before: Optional[str] = None) -> Page:
        if not self.items:
            return Page(items=[], next_cursor=None, prev_cursor=None)

        if after:
            after_id = decode_cursor(after)
            start_idx = next((i for i, item in enumerate(self.items) if item['id'] > after_id), len(self.items))
        elif before:
            before_id = decode_cursor(before)
            end_idx = next((i for i, item in enumerate(self.items) if item['id'] >= before_id), 0)
            start_idx = max(0, end_idx - self.page_size)
        else:
            start_idx = 0

        if before:
            before_id = decode_cursor(before)
            end_idx = next((i for i, item in enumerate(self.items) if item['id'] >= before_id), 0)
            page_items = self.items[start_idx:end_idx]
        else:
            page_items = self.items[start_idx:start_idx + self.page_size]

        next_cursor = None
        prev_cursor = None

        if page_items:
            last_id = page_items[-1]['id']
            first_id = page_items[0]['id']
            # Check if there are more items after
            remaining = [item for item in self.items if item['id'] > last_id]
            if remaining:
                next_cursor = encode_cursor(last_id)
            # Check if there are items before
            preceding = [item for item in self.items if item['id'] < first_id]
            if preceding:
                prev_cursor = encode_cursor(first_id)

        return Page(items=page_items, next_cursor=next_cursor, prev_cursor=prev_cursor)
